CREATE OR REPLACE FUNCTION fpb_skl_get_memloan_by_date ( adt_date timestamp(0) , as_loan_code char) RETURNS bigint AS $body$
DECLARE

li_memloan integer;

BEGIN

  select count(distinct membership_no )
  into STRICT  li_memloan
	from  sc_rep_mem_share_loan_bal
	where balance_date = adt_date
	and	  emer_loan_code = as_loan_code
  and   emer_balance > 0 	
;

  if coalesce(li_memloan::text, '') = '' then
    li_memloan := 0;
  end if;

  RETURN li_memloan;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
